(function(){'use strict';const BATCH_SIZE=60;const INITIAL=60;const TRAIL_KEYS=['pct','at','ebc','tmb','colorado','pinhoti','trt','uinta','lost-coast','bmt','eagle-rock','escalante','whitney','shasta'];function buildList(keys){const list=[];keys.forEach(key=>{const cat=GALLERY_DATA[key];if(!cat)return;cat.images.forEach(src=>list.push({src,category:key,label:cat.label}));});return list;}function seededShuffle(arr){const a=[...arr];for(let i=a.length-1;i>0;i--){const j=Math.abs((i*6364136223846793005+1442695040888963407)%(i+1));const jj=j%(i+1);[a[i],a[jj]]=[a[jj],a[i]];}return a;}const allTrailPhotos=seededShuffle(buildList(TRAIL_KEYS));document.getElementById('count-all').textContent=allTrailPhotos.length;TRAIL_KEYS.forEach(key=>{const el=document.getElementById(`count-${key}`);if(el&&GALLERY_DATA[key])el.textContent=GALLERY_DATA[key].images.length;});function GalleryManager({gridId,loadMoreId,showingId,allPhotos}){const grid=document.getElementById(gridId);const loadMoreBtn=document.getElementById(loadMoreId);const showingEl=document.getElementById(showingId);let currentFilter='all';let filteredPhotos=[];let renderedCount=0;const imgObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){const img=entry.target;if(img.dataset.src){const full=new Image();full.onload=()=>{img.src=img.dataset.src;delete img.dataset.src;img.classList.add('loaded');};full.src=img.dataset.src;imgObserver.unobserve(img);}}});},{rootMargin:'400px 0px'});function createItem(photo,idx){const div=document.createElement('div');div.className='masonry-item';div.dataset.index=idx;const img=document.createElement('img');img.dataset.src=photo.src;img.src='data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 4 3"><rect fill="%23241e16" width="4" height="3"/></svg>';img.alt=photo.label;img.loading='lazy';img.className='blur-up';img.width=4;img.height=3;const overlay=document.createElement('div');overlay.className='item-overlay';const catSpan=document.createElement('span');catSpan.className='item-category';catSpan.textContent=photo.label;overlay.appendChild(catSpan);div.appendChild(img);div.appendChild(overlay);div.addEventListener('click',()=>openLightbox(idx,filteredPhotos));imgObserver.observe(img);return div;}function renderBatch(count){const start=renderedCount;const end=Math.min(start+count,filteredPhotos.length);const frag=document.createDocumentFragment();for(let i=start;i<end;i++){frag.appendChild(createItem(filteredPhotos[i],i));}grid.appendChild(frag);renderedCount=end;updateShowing();if(loadMoreBtn){loadMoreBtn.classList.toggle('hidden',renderedCount>=filteredPhotos.length);}}function applyFilter(filter,allPhotos){currentFilter=filter;filteredPhotos=filter==='all'?allPhotos:allPhotos.filter(p=>p.category===filter);grid.innerHTML='';renderedCount=0;renderBatch(INITIAL);}function updateShowing(){if(showingEl)showingEl.textContent=`Showing ${renderedCount} of ${filteredPhotos.length} photos`;}if(loadMoreBtn){loadMoreBtn.addEventListener('click',()=>renderBatch(BATCH_SIZE));}return{applyFilter,getFiltered:()=>filteredPhotos,allPhotos};}const lightbox=document.getElementById('lightbox');const lbImg=document.getElementById('lb-img');const lbCaption=document.getElementById('lb-caption');const lbCounter=document.getElementById('lb-counter');const lbSpinner=document.getElementById('lb-spinner');const lbClose=document.getElementById('lb-close');const lbPrev=document.getElementById('lb-prev');const lbNext=document.getElementById('lb-next');let lbIndex=0;let lbPhotos=[];function openLightbox(index,photos){lbIndex=index;lbPhotos=photos;lightbox.classList.add('open');lightbox.setAttribute('aria-hidden','false');document.body.style.overflow='hidden';loadLbImage(index);}function closeLightbox(){lightbox.classList.remove('open');lightbox.setAttribute('aria-hidden','true');document.body.style.overflow='';lbImg.src='';}function loadLbImage(index){const photo=lbPhotos[index];if(!photo)return;lbImg.classList.add('loading');lbSpinner.classList.add('visible');lbCaption.textContent=photo.label;lbCounter.textContent=`${index+1} / ${lbPhotos.length}`;const pre=new Image();pre.onload=pre.onerror=()=>{lbImg.src=photo.src;lbImg.classList.remove('loading');lbSpinner.classList.remove('visible');};pre.src=photo.src;}function lbPrevPhoto(){lbIndex=(lbIndex-1+lbPhotos.length)%lbPhotos.length;loadLbImage(lbIndex);}function lbNextPhoto(){lbIndex=(lbIndex+1)%lbPhotos.length;loadLbImage(lbIndex);}lbClose.addEventListener('click',closeLightbox);lbPrev.addEventListener('click',lbPrevPhoto);lbNext.addEventListener('click',lbNextPhoto);lightbox.addEventListener('click',e=>{if(e.target===lightbox)closeLightbox();});document.addEventListener('keydown',e=>{if(!lightbox.classList.contains('open'))return;if(e.key==='Escape')closeLightbox();if(e.key==='ArrowLeft')lbPrevPhoto();if(e.key==='ArrowRight')lbNextPhoto();});let touchStartX=0;lightbox.addEventListener('touchstart',e=>{touchStartX=e.touches[0].clientX;},{passive:true});lightbox.addEventListener('touchend',e=>{const dx=e.changedTouches[0].clientX-touchStartX;if(Math.abs(dx)>50){dx<0?lbNextPhoto():lbPrevPhoto();}},{passive:true});const trailGallery=GalleryManager({gridId:'gallery-grid',loadMoreId:'load-more-btn',showingId:'gallery-showing',allPhotos:allTrailPhotos});trailGallery.applyFilter('all',allTrailPhotos);document.querySelectorAll('[data-gallery="trails"].filter-btn').forEach(btn=>{btn.addEventListener('click',()=>{document.querySelectorAll('[data-gallery="trails"].filter-btn').forEach(b=>b.classList.remove('active'));btn.classList.add('active');trailGallery.applyFilter(btn.dataset.filter,allTrailPhotos);const wrap=document.getElementById('trail-filters-wrap');if(wrap)window.scrollTo({top:wrap.offsetTop-80,behavior:'smooth'});});});})();
